## Wrapping Callback APIs

Many Node core modules still use callbacks. You can wrap them with promises:

```javascript
const fs = require('fs');

function readFilePromise(path, encoding) {
  return new Promise((resolve, reject) => {
    fs.readFile(path, encoding, (err, data) => {
      if (err) reject(err);
      else resolve(data);
    });
  });
}

readFilePromise('file.txt', 'utf8')
  .then(data => console.log(data))
  .catch(err => console.error(err));
```

Node also provides `fs.promises` which does this for you.
